async function safeAPICall(prompt: string): Promise<string> {
  let response: Response;

  try {
    response = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${process.env.OPENAI_API_KEY}`,
      },
      body: JSON.stringify({
        model: "gpt-4",
        messages: [{ role: "user", content: prompt }],
      }),
    });
  } catch (networkError) {
    // This only fires for actual network failures (DNS error, no internet, etc.)
    throw new Error(`Network error: ${networkError}`);
  }

  if (!response.ok) {
    // Read the error body to get a useful message
    const errorBody = await response.json().catch(() => ({}));
    throw new Error(
      `API error ${response.status}: ${JSON.stringify(errorBody)}`
    );
  }

  const data = await response.json() as OpenAIResponse;
  return data.choices[0].message.content;
}

async function fetchWithRetry(
  url: string,
  options: RequestInit,
  maxRetries = 3
): Promise<Response> {
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    const response = await fetch(url, options);

    // Success or a client error (4xx, except 429) — don't retry
    if (response.ok || (response.status >= 400 && response.status < 500 && response.status !== 429)) {
      return response;
    }

    // 429 or 5xx — wait and retry
    const delay = Math.pow(2, attempt) * 1000; // 1s, 2s, 4s
    console.warn(`Attempt ${attempt + 1} failed (${response.status}). Retrying in ${delay}ms...`);
    await new Promise(resolve => setTimeout(resolve, delay));
  }

  throw new Error(`Request failed after ${maxRetries} attempts`);
}

async function streamCompletion(prompt: string): Promise<void> {
  const response = await fetch("https://api.openai.com/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${process.env.OPENAI_API_KEY}`,
    },
    body: JSON.stringify({
      model: "gpt-4",
      messages: [{ role: "user", content: prompt }],
      stream: true, // Enable streaming
    }),
  });

  if (!response.ok || !response.body) {
    throw new Error(`Stream failed: ${response.status}`);
  }

  const reader = response.body.getReader();
  const decoder = new TextDecoder();

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;

    const chunk = decoder.decode(value);
    const lines = chunk.split("\n").filter(line => line.startsWith("data: "));

    for (const line of lines) {
      const jsonStr = line.replace("data: ", "").trim();
      if (jsonStr === "[DONE]") return;

      try {
        const parsed = JSON.parse(jsonStr);
        const token = parsed.choices?.[0]?.delta?.content;
        if (token) process.stdout.write(token); // Print each token as it arrives
      } catch {
        // Skip malformed chunks
      }
    }
  }
}

